code.C:
#include <stdio.h>

union Numbers {
    int num1;
    int num2;
};

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        union Numbers n;
        scanf("%d", &n.num1);
        printf("First Number: %d\n", n.num1);
        scanf("%d", &n.num2);
        printf("Second Number: %d\n", n.num2);
        if (tc != T - 1) printf("\n");
    }
    return 0;
}

